13	interface QuoteStep {
14	  op: "quote";
15	  items: { type: string }[];
16	}
17	
18	interface Scenario {
19	  customer: { yearsWithMHPCO: number };
20	  steps: QuoteStep[];
21	}
22	
23	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
24	const COMPONENT_BASE = 25;
25	const BLOCK_SIZE = 3;
26	const BLOCK_BASE = 60;
27	
28	const componentBase = (count: number): number => {
29	  const blocks = Math.floor(count / BLOCK_SIZE);
30	  const singles = count % BLOCK_SIZE;
31	  return blocks * BLOCK_BASE + singles * COMPONENT_BASE;
32	};
33	
34	const baseForItems = (items: { type: string }[]): number => {
35	  const componentCounts = new Map<string, number>();
36	  let total = 0;
37	  for (const item of items) {
38	    if (COMPONENT_TYPES.has(item.type)) {
39	      componentCounts.set(item.type, (componentCounts.get(item.type) ?? 0) + 1);
40	    } else {
41	      total += BASE_PREMIUMS[item.type] ?? 0;
42	    }
43	  }
44	  for (const count of componentCounts.values()) {
45	    total += componentBase(count);
46	  }
47	  return total;
48	};
49	
50	const priceQuote = (items: { type: string }[]): { premium: number } => {
51	  const policyBase = baseForItems(items);
52	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_RATE;
53	  const premium = Math.ceil(
54	    policyBase + firstInsuranceSurcharge + PROCESSING_FEE,
55	  );
56	  return { premium };
57	};
58	
59	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
60	  const results = scenario.steps.map((step) => priceQuote(step.items));
61	  return { results };
62	};
